toolInput.sketch:
int count = 0;
int btnAddPin = 9;
int btnSubPin = 10;
int lastAddState = HIGH;
int lastSubState = HIGH;

int segA = 2;
int segB = 3;
int segC = 4;
int segD = 5;
int segE = 6;
int segF = 7;
int segG = 8;

void setup() {
  pinMode(btnAddPin, INPUT_PULLUP);
  pinMode(btnSubPin, INPUT_PULLUP);
  pinMode(segA, OUTPUT);
  pinMode(segB, OUTPUT);
  pinMode(segC, OUTPUT);
  pinMode(segD, OUTPUT);
  pinMode(segE, OUTPUT);
  pinMode(segF, OUTPUT);
  pinMode(segG, OUTPUT);
  displayDigit(count);
}

void loop() {
  int addState = digitalRead(btnAddPin);
  int subState = digitalRead(btnSubPin);

  if (addState == LOW && lastAddState == HIGH) {
    if (count < 9) {
      count++;
      displayDigit(count);
    }
  }

  if (subState == LOW && lastSubState == HIGH) {
    if (count > 0) {
      count--;
      displayDigit(count);
    }
  }

  lastAddState = addState;
  lastSubState = subState;
  delay(20);
}

void displayDigit(int digit) {
  if (digit == 0) {
    digitalWrite(segA, HIGH);
    digitalWrite(segB, HIGH);
